.darma-loader-button-dots {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  border-radius: 999px;
  background: var(--loader-color, #6366f1);
  padding: 12px 18px;
  color: #fff;
}
.darma-loader-button-dots i {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: currentColor;
  animation: darma-loader-button-dots-blink 0.95s ease-in-out infinite;
}
.darma-loader-button-dots i:nth-child(2) { animation-delay: 0.15s; }
.darma-loader-button-dots i:nth-child(3) { animation-delay: 0.3s; }
@keyframes darma-loader-button-dots-blink {
  0%, 100% { opacity: 0.28; transform: scale(0.8); }
  50% { opacity: 1; transform: scale(1); }
}

.darma-loader-uiverse-button-save-dots {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 5px;
      min-width: 36px;
      min-height: 14px;
    }
    .darma-loader-uiverse-button-save-dots i {
      display: block;
      width: 7px;
      height: 7px;
      border-radius: 50%;
      background: var(--loader-color, #0ea5e9);
      animation: darma-loader-uiverse-button-save-dots-dotPulse 0.72s ease-in-out infinite;
    }
    .darma-loader-uiverse-button-save-dots i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-uiverse-button-save-dots i:nth-child(2) { animation-delay: 0.12s; }
.darma-loader-uiverse-button-save-dots i:nth-child(3) { animation-delay: 0.24s; }
    @keyframes darma-loader-uiverse-button-save-dots-dotPulse { 0%, 80%, 100% { transform: translateY(0) scale(.75); opacity: .45; } 40% { transform: translateY(-8px) scale(1); opacity: 1; } }

.darma-loader-button-spinner {
  display: inline-block;
  width: 26px;
  height: 26px;
  border-radius: 50%;
  border: 3px solid color-mix(in srgb, var(--loader-color, #6366f1) 20%, transparent);
  border-right-color: var(--loader-color, #6366f1);
  animation: darma-loader-button-spinner-spin 0.7s linear infinite;
}
@keyframes darma-loader-button-spinner-spin { to { transform: rotate(360deg); } }

.darma-loader-uiverse-orbital-button-spinner {
      position: relative;
      display: inline-block;
      width: 34px;
      height: 34px;
      border-radius: 50%;
      border: 1px solid color-mix(in srgb, var(--loader-color, #ec4899) 24%, transparent);
    }
    .darma-loader-uiverse-orbital-button-spinner i {
      position: absolute;
      inset: -3px;
      border-radius: 50%;
      animation: darma-loader-uiverse-orbital-button-spinner-orbit 0.8s linear infinite;
    }
    .darma-loader-uiverse-orbital-button-spinner i::before {
      content: "";
      position: absolute;
      top: 0;
      left: 50%;
      width: 10px;
      height: 10px;
      margin-left: -5px;
      border-radius: 50%;
      background: var(--loader-color, #ec4899);
      box-shadow: 0 0 18px color-mix(in srgb, var(--loader-color, #ec4899) 45%, transparent);
    }
    .darma-loader-uiverse-orbital-button-spinner i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-uiverse-orbital-button-spinner i:nth-child(2) { animation-delay: -0.40s; }
    @keyframes darma-loader-uiverse-orbital-button-spinner-orbit { to { transform: rotate(360deg); } }

.darma-loader-darma-research-orbital-upload-rings { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #3b82f6); --accent-2: var(--loader-secondary-color, #22c55e); border: 0; color: #fff; background: #111827; border-radius: 999px; padding: 12px 18px 12px 46px; min-width: 132px; position: relative; font: 800 14px/1 system-ui, sans-serif; box-shadow: inset 0 0 0 1px #ffffff1a, 0 12px 25px #0206173d; }
.darma-loader-darma-research-orbital-upload-rings__ring { position: absolute; left: 12px; top: 50%; width: 22px; height: 22px; margin-top: -11px; border-radius: 50%; border: 3px solid color-mix(in srgb, var(--accent) 25%, transparent); border-top-color: var(--accent); animation: darma-loader-darma-research-orbital-upload-rings-upload-ring calc(var(--speed) * .9) linear infinite; }
.darma-loader-darma-research-orbital-upload-rings__arrow { position: absolute; left: 18px; top: 50%; translate: 0 -50%; color: var(--accent-2); animation: darma-loader-darma-research-orbital-upload-rings-upload-arrow calc(var(--speed) * 1.1) ease-in-out infinite; }
.darma-loader-darma-research-orbital-upload-rings__text { background: linear-gradient(90deg, var(--accent), var(--accent-2)); -webkit-background-clip: text; background-clip: text; color: transparent; }
@keyframes darma-loader-darma-research-orbital-upload-rings-upload-ring { to { rotate: 360deg; } }
@keyframes darma-loader-darma-research-orbital-upload-rings-upload-arrow { 50% { transform: translateY(-5px); opacity:.65; } }
